const normalizeArray = (value) => {
  if (Array.isArray(value)) return value;
  if (typeof value === 'string' && value.trim()) {
    try {
      const parsed = JSON.parse(value);
      if (Array.isArray(parsed)) return parsed;
    } catch {}

    return value
      .replace(/^{/, '')
      .replace(/}$/, '')
      .split(',')
      .map((entry) => entry.trim())
      .filter(Boolean);
  }
  return [];
};

const topic = $('Postgres : Réserver 1 Sujet SEO').first().json;
const selection = items[0]?.json ?? {};

const rawProducts = normalizeArray(selection.products)
  .map((product) => {
    if (typeof product === 'string') {
      try {
        return JSON.parse(product);
      } catch {
        return null;
      }
    }
    return product;
  })
  .filter(Boolean);

const rawProductIds = normalizeArray(selection.product_ids).map((id) => String(id)).filter(Boolean);
const uniqueProductIds = [...new Set(rawProductIds)];

const productsText = rawProducts.length > 0
  ? rawProducts
      .map((product) => '- [' + product.id + '] ' + product.title + ' (Prix catalogue exact : ' + (product.prix_calcule ?? 'N/A') + '€)')
      .join('
')
  : 'Aucun produit imposé pour ce sujet. Ne recommande aucun accessoire si la liste est vide.';

const topicTitle = topic.title || 'Sujet SEO du Journal';
const targetKeyword = topic.target_keyword || 'Non précisé';
const secondaryKeywords = topic.secondary_keywords || 'Aucun';
const searchIntent = topic.search_intent || 'informational';
const pillar = topic.pillar || 'general';
const articleType = topic.article_type || 'guide';
const angle = topic.angle || 'Aucun angle imposé';
const audience = topic.audience || 'Grand public';
const brief = topic.brief || 'Répondre clairement au besoin de l\'internaute.';
const seasonality = topic.seasonality || 'evergreen';
const minWords = Math.min(500, Math.max(400, Number(topic.min_words || 450)));
const maxProducts = Number(topic.max_products || 4);

const prompt = [
  'Sujet SEO validé pour le Journal Koktek :',
  'Titre interne : ' + topicTitle,
  'Mot-clé principal : ' + targetKeyword,
  'Mots-clés secondaires : ' + secondaryKeywords,
  'Intention : ' + searchIntent,
  'Pilier : ' + pillar,
  'Type d\'article : ' + articleType,
  'Angle : ' + angle,
  'Audience : ' + audience,
  'Saisonnalité : ' + seasonality,
  'Brief : ' + brief,
  'Longueur cible : 400 à 500 mots (viser ' + minWords + ' mots).',
  'Nombre maximum de produits à citer : ' + maxProducts,
  '',
  'Produits Koktek disponibles si et seulement si pertinents :',
  productsText,
  '',
  'Consignes :',
  '1. Répondre d\'abord au problème de l\'internaute, sans ton publicitaire.',
  '2. Produire un article snackable : court, dense, utile et immédiatement actionnable.',
  '3. Ne jamais transformer l\'article en fiche produit déguisée.',
  '4. N\'inventer aucun produit, accessoire ou usage absent de la liste fournie.',
  '5. Si des produits sont pertinents, les citer surtout dans la deuxième moitié ou la conclusion.',
  '6. Ne jamais écrire de prix chiffré dans le corps du texte : laisser le bloc produit afficher le prix catalogue exact.',
  '7. Si la marque apparaît dans le corps du texte, écrire toujours "Koktek", jamais "KOKTEK".',
  '8. Limiter la marque à une seule mention, si possible dans la conclusion.',
  '9. Utiliser du HTML propre avec des <h2>, <h3>, <p>, <ul>, <li> et <strong>.',
  '10. Utiliser des paragraphes courts, du gras utile et au moins une liste à puces.',
  '11. Aucun bloc ne doit dépasser 3 phrases sans rupture visuelle.',
  '12. La cover doit toujours être une image lifestyle Pexels : jamais de packshot produit, jamais d\'accessoire isolé, jamais de visuel bijou ou mode.',
  '13. Les images produit restent reservees au bloc Produits recommandes, jamais a la une.',
  '14. Fournir un cover_image_query lifestyle, crédible et neutre. En cas de doute, choisir une scène d\'usage simple et universelle.',
  '15. L\'article sera publié automatiquement, donc éviter tout placeholder ou formulation hésitante.',
  '16. Renvoyer strictement l\'objet JSON brut, rien d\'autre.',
].join('
');

return [{
  json: {
    topic_id: topic.id,
    topic_title: topicTitle,
    target_keyword: topic.target_keyword || '',
    secondary_keywords: topic.secondary_keywords || '',
    search_intent: searchIntent,
    pillar: topic.pillar || '',
    article_type: articleType,
    angle: topic.angle || '',
    audience: topic.audience || '',
    brief: topic.brief || '',
    seasonality,
    min_words: minWords,
    max_products: maxProducts,
    products: rawProducts,
    products_text: productsText,
    product_ids: uniqueProductIds,
    cover_image: null,
    prompt,
  }
}];

const toSlug = (value) => value
  .toLowerCase()
  .normalize('NFD')
  .replace(/[̀-ͯ]/g, '')
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/(^-|-$)+/g, '');

const stripHtml = (value) => value
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const normalizeIds = (value) => {
  if (Array.isArray(value)) return value.map((id) => String(id)).filter(Boolean);
  if (typeof value === 'string' && value.trim()) {
    return value
      .replace(/^{/, '')
      .replace(/}$/, '')
      .split(',')
      .map((entry) => entry.trim())
      .filter(Boolean);
  }
  return [];
};

const stripBrandFromTitle = (value) => {
  if (typeof value !== 'string') return '';
  return value
    .replace(/ KOKTEK /gi, '')
    .replace(/\s{2,}/g, ' ')
    .replace(/\s+([:!?;])/g, '$1')
    .replace(/(^[-:|\s]+|[-:|\s]+$)/g, '')
    .trim();
};

const normalizeBrandCase = (value) => {
  if (typeof value !== 'string') return '';
  return value.replace(/ koktek /gi, 'Koktek');
};

const keepSingleBrandMention = (value) => {
  if (typeof value !== 'string' || !value) return '';
  const matches = [...value.matchAll(/ koktek /gi)];
  if (matches.length === 0) return value;

  let cursor = 0;
  let result = '';

  matches.forEach((match, index) => {
    const start = match.index ?? 0;
    const end = start + match[0].length;
    result += value.slice(cursor, start);
    result += index === matches.length - 1 ? 'Koktek' : 'la marque';
    cursor = end;
  });

  return result + value.slice(cursor);
};

const sanitizeBrandMentions = (value) => keepSingleBrandMention(normalizeBrandCase(value));

const inferCoverQuery = (preparedData, safeTitle) => {
  const keyword = String(preparedData.target_keyword || '').toLowerCase();

  if (keyword.includes('voiture') || keyword.includes('gps')) return 'car dashboard lifestyle';
  if (keyword.includes('ecouteur') || keyword.includes('earbud') || keyword.includes('airpod')) return 'clean wireless earbuds on desk';
  if (keyword.includes('coque')) return 'smartphone on clean desk';
  if (keyword.includes('charge') || keyword.includes('batterie')) return 'phone charging on desk';
  if (keyword.includes('courir') || keyword.includes('running') || keyword.includes('sport')) return 'person running outdoors';

  const byPillar = {
    'auto-mobilite': 'car dashboard lifestyle',
    'tech-productivite': 'organized desk smartphone',
    'lifestyle-protection': 'smartphone everyday lifestyle',
    'creation-mobile': 'mobile content creator',
    'guides-achat': 'smartphone accessories lifestyle',
  };

  return byPillar[preparedData.pillar] || stripBrandFromTitle(preparedData.target_keyword || '') || safeTitle;
};

const sanitizeCoverQuery = (value, preparedData, safeTitle) => {
  const blockedTerms = / (diamond|diamant|glitter|jewel|jewelry|bracelet|necklace|ring|makeup|cosmetic|nail|fashion|luxury|sparkle|gem|rhinestone|mockup|template|isolated|render) /i;
  const cleaned = stripBrandFromTitle(typeof value === 'string' ? value : '')
    .replace(/[^a-zA-Z0-9\s-]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

  if (!cleaned || blockedTerms.test(cleaned) || cleaned.split(/\s+/).length > 7) {
    return inferCoverQuery(preparedData, safeTitle);
  }

  return cleaned;
};

let aiText = items[0].json.output || items[0].json.text || items[0].json.message?.content || items[0].json.message || '';

if (typeof aiText !== 'string' || !aiText.trim()) {
  throw new Error('La réponse du modèle est vide ou illisible.');
}

aiText = aiText.replace(/```json/gi, '').replace(/```/g, '').trim();

const start = aiText.indexOf('{');
const end = aiText.lastIndexOf('}');
const jsonSlice = start !== -1 && end !== -1 && end > start
  ? aiText.slice(start, end + 1)
  : aiText;

let aiResponse;
try {
  aiResponse = JSON.parse(aiText);
} catch {
  aiResponse = JSON.parse(jsonSlice);
}

const preparedData = $('Code : Préparer Brief SEO').first().json;
const topicTitle = stripBrandFromTitle(preparedData.topic_title || '') || 'Article du Journal';
const title = stripBrandFromTitle(typeof aiResponse.title === 'string' ? aiResponse.title.trim() : '');
const safeTitle = title || topicTitle;
const safeSlug = toSlug((typeof aiResponse.slug === 'string' ? aiResponse.slug : safeTitle) || 'article-journal');
const summary = sanitizeBrandMentions(typeof aiResponse.excerpt === 'string' ? aiResponse.excerpt.trim() : '');
const content = sanitizeBrandMentions(typeof aiResponse.content === 'string' ? aiResponse.content.trim() : '');
const seoTitle = stripBrandFromTitle(typeof aiResponse.seo_title === 'string' ? aiResponse.seo_title.trim() : '') || safeTitle;
const seoDescription = normalizeBrandCase(typeof aiResponse.seo_description === 'string' ? aiResponse.seo_description.trim() : summary);
const coverImageAlt = normalizeBrandCase(typeof aiResponse.cover_image_alt === 'string' ? aiResponse.cover_image_alt.trim() : safeTitle);
const coverImageQuery = sanitizeCoverQuery(aiResponse.cover_image_query, preparedData, safeTitle);
const productIds = normalizeIds(preparedData.product_ids);
const coverImage = preparedData.cover_image || null;

if (!content) {
  throw new Error('L'article généré ne contient aucun contenu exploitable.');
}

const wordCount = stripHtml(content).split(/\s+/).filter(Boolean).length;
const readingTime = Math.max(1, Math.ceil(wordCount / 220));

return [{
  json: {
    topic_id: preparedData.topic_id,
    title: safeTitle,
    slug: safeSlug,
    summary,
    content,
    cover_image: coverImage,
    cover_image_alt: coverImageAlt,
    cover_image_query: coverImageQuery,
    product_ids: productIds,
    pillar: preparedData.pillar || null,
    article_type: preparedData.article_type || null,
    reading_time: readingTime,
    target_keyword: preparedData.target_keyword || null,
    search_intent: preparedData.search_intent || null,
    seasonality: preparedData.seasonality || null,
    author_label: 'Journal KOKTEK',
    seo_title: seoTitle,
    seo_description: seoDescription,
  }
}];

const blogPostId = items[0].json.id;
const productIds = $('Code : Parser le JSON').first().json.product_ids || [];

return productIds.map((productId) => ({
  json: {
    blog_posts_id: blogPostId,
    products_id: productId,
  }
}));

const article = $('Code : Parser le JSON').first().json;
const response = items[0]?.json ?? {};
const photos = Array.isArray(response.photos) ? response.photos : [];
const queryTerms = String(article.cover_image_query || '')
  .toLowerCase()
  .split(/[^a-z0-9]+/)
  .filter(Boolean)
  .slice(0, 6);

const blockedTerms = [
  'diamond', 'diamant', 'glitter', 'jewel', 'jewelry', 'bracelet', 'necklace', 'ring',
  'makeup', 'cosmetic', 'nail', 'fashion', 'luxury', 'sparkle', 'gem', 'rhinestone',
  'mockup', 'template', 'isolated', 'render', 'sticker', 'ornament', 'decorative'
];

const productLikeTerms = ['case', 'cover', 'coque', 'packshot', 'product'];
const lifestyleTerms = ['lifestyle', 'desk', 'workspace', 'dashboard', 'interior', 'outdoor', 'person', 'hands', 'smartphone', 'phone', 'charging', 'earbuds', 'clean', 'running', 'car'];
const wantsHumanScene = /courir|running|sport|selfie|creator|photo/.test(String(article.target_keyword || '').toLowerCase());
const coverFallbacks = [
  { matcher: /(coque|protection|magsafe|magnetique|antichoc|transparent)/i, url: 'https://images.pexels.com/photos/442576/pexels-photo-442576.jpeg?auto=compress&cs=tinysrgb&dpr=2&h=1100&w=825' },
  { matcher: /(chargeur|charge|batterie|usb|power|induction|gan)/i, url: 'https://images.pexels.com/photos/4526407/pexels-photo-4526407.jpeg?auto=compress&cs=tinysrgb&dpr=2&h=1100&w=825' },
  { matcher: /(voiture|auto|gps|moto|navigation)/i, url: 'https://images.pexels.com/photos/694424/pexels-photo-694424.jpeg?auto=compress&cs=tinysrgb&dpr=2&h=1100&w=825' },
  { matcher: /(selfie|creator|creation|photo|video|tr[eé]pied|capture)/i, url: 'https://images.pexels.com/photos/774909/pexels-photo-774909.jpeg?auto=compress&cs=tinysrgb&dpr=2&h=1100&w=825' },
  { matcher: /(ecouteur|audio|casque|earbud)/i, url: 'https://images.pexels.com/photos/3780681/pexels-photo-3780681.jpeg?auto=compress&cs=tinysrgb&dpr=2&h=1100&w=825' },
];

const scorePhoto = (photo) => {
  if (!photo || typeof photo !== 'object') return -999;
  const src = photo.src || {};
  const imageUrl = src.large2x || src.large || src.original || src.medium;
  if (!imageUrl) return -999;

  const alt = String(photo.alt || '').toLowerCase();
  const photographer = String(photo.photographer || '').toLowerCase();
  const haystack = [alt, photographer].join(' ');

  let score = 0;
  const width = Number(photo.width || 0);
  const height = Number(photo.height || 0);

  if (height >= width * 0.9) score += 4;
  if (height >= 1200) score += 3;
  if (width >= 700) score += 1;

  for (const term of queryTerms) {
    if (term && haystack.includes(term)) score += 1;
  }

  for (const term of lifestyleTerms) {
    if (haystack.includes(term)) score += 1;
  }

  for (const term of blockedTerms) {
    if (haystack.includes(term)) score -= 8;
  }

  for (const term of productLikeTerms) {
    if (haystack.includes(term)) score -= 5;
  }

  if (wantsHumanScene && /(person|people|woman|man|runner|jogging|outdoor|fitness)/.test(haystack)) {
    score += 4;
  }

  if (!wantsHumanScene && /(workspace|desk|interior|dashboard|charging|smartphone|hands)/.test(haystack)) {
    score += 3;
  }

  return score;
};

const ranked = [...photos]
  .filter((photo) => photo?.src?.large2x || photo?.src?.large || photo?.src?.original || photo?.src?.medium)
  .sort((left, right) => scorePhoto(right) - scorePhoto(left));

const bestPhoto = ranked[0];
const bestScore = bestPhoto ? scorePhoto(bestPhoto) : -999;
const src = bestPhoto?.src || {};
const bestUrl = src.large2x || src.large || src.original || src.medium || null;
const fallbackHaystack = [article.target_keyword, article.pillar, article.title].filter(Boolean).join(' ');
const fallbackCover = coverFallbacks.find((entry) => entry.matcher.test(fallbackHaystack))?.url || 'https://images.pexels.com/photos/4526407/pexels-photo-4526407.jpeg?auto=compress&cs=tinysrgb&dpr=2&h=1100&w=825';
const finalCover = bestScore >= 5 ? bestUrl : fallbackCover;

return [{
  json: {
    ...article,
    cover_image: finalCover,
    cover_image_source: 'pexels',
    cover_image_provider: 'pexels',
    cover_image_credit: bestScore >= 5 ? bestPhoto?.photographer ?? null : null,
  }
}];
